import anthropic
import json

client = anthropic.Anthropic()

# Define a tool that forces the model to return a specific schema
CLASSIFICATION_TOOL = {
    "name": "classify_sentiment",
    "description": "Classify the sentiment of the given text.",
    "input_schema": {
        "type": "object",
        "properties": {
            "sentiment": {
                "type": "string",
                "enum": ["positive", "negative", "neutral"],
                "description": "The sentiment classification."
            },
            "confidence": {
                "type": "number",
                "minimum": 0.0,
                "maximum": 1.0,
                "description": "Confidence score from 0.0 to 1.0."
            },
            "key_phrases": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Key phrases that influenced the classification."
            }
        },
        "required": ["sentiment", "confidence", "key_phrases"]
    }
}

def classify_with_forced_schema(text: str) -> dict:
    """
    Use tool_choice='any' to force the model into a specific token vocabulary.
    This is the logit-bias equivalent: the model MUST use enum values only.
    """
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        tools=[CLASSIFICATION_TOOL],
        tool_choice={"type": "tool", "name": "classify_sentiment"},
        messages=[
            {"role": "user", "content": f"Classify this text: {text}"}
        ]
    )

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    return {}

texts = [
    "The product exceeded all my expectations!",
    "It was okay, nothing special.",
    "Worst purchase I have ever made."
]

for text in texts:
    result = classify_with_forced_schema(text)
    print(f"Text: {text[:40]}...")
    print(f"  Sentiment: {result.get('sentiment')}")
    print(f"  Confidence: {result.get('confidence'):.2f}")
    print(f"  Key phrases: {result.get('key_phrases')}")
    print()
